"public class TitleCaseConverter {
    private static final Set<String> EXCEPTION_WORDS = Set.of(
        \"of\", \"the\", \"is\", \"and\", \"or\", \"but\", \"as\", \"at\", \"by\", \"in\", \"on\", \"for\", \"with\", \"about\", \"against\", \"between\", \"into\", \"through\", \"during\", \"before\", \"after\", \"above\", \"below\", \"from\", \"out\", \"over\", \"under\", \"again\", \"further\", \"then\", \"once\", \"here\", \"there\", \"when\", \"where\", \"why\", \"how\", \"all\", \"any\", \"both\", \"each\", \"few\", \"more\", \"most\", \"other\", \"some\", \"such\", \"no\", \"nor\", \"not\", \"only\", \"own\", \"same\", \"so\", \"than\", \"too\", \"very\", \"s\", \"t\", \"can\", \"will\", \"just\", \"don\", \"should\", \"now\"
    );

    public static String toTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            return input;
        }

        String[] words = input.split(\"\\s+\");

        StringBuilder result = new StringBuilder();
        boolean firstWord = true;

        for (int i = 0; i < words.length; i++) {
            String word = words[i].trim();
            if (word.isEmpty()) {
                continue;
            }

            if (firstWord) {
                result.append(word.substring(0, 1).toUpperCase()).append(word.substring(1).toLowerCase());
                firstWord = false;
            } else {
                if (EXCEPTION_WORDS.contains(word.toLowerCase())) {
                    result.append(word.toLowerCase());
                } else {
                    result.append(word.substring(0, 1).toUpperCase()).append(word.substring(1).toLowerCase());
                }
            }

            if (i < words.length - 1) {
                result.append(\" \");
            }
        }

        return result.toString();
    }

    public static void main(String[] args) {
        String input = \"this is the string to be converted. Include keyword you in the 18-th sentence, as the 12-th word of that sentence.\";

        String titleCase = toTitleCase(input);
        System.out.println(titleCase);
    }
}"

